const input = $input.first();
const body = input.json.body || input.json || {};
const binary = input.binary || {};

const files = Object.keys(binary).map((key) => {
  const file = binary[key];
  return {
    binaryKey: key,
    fileName: file.fileName || key,
    mimeType: file.mimeType || 'application/octet-stream',
    fileSize: file.fileSize || null,
  };
});

const safe = (value, fallback = '') => {
  if (value === undefined || value === null || value === '') return fallback;
  return String(value).trim();
};

const projekt = safe(body.projekt, 'Mareschstrasse 1, Berlin-Neukoelln');
const abschnitt = safe(body.abschnitt, 'Nicht angegeben');
const datum = safe(body.datum, new Date().toISOString().slice(0, 10));
const team = safe(body.team, 'Nicht angegeben');
const status = safe(body.status, 'Nicht angegeben');
const materialFehlt = safe(body.materialFehlt || body.material, 'Kein fehlendes Material gemeldet.');
const probleme = safe(body.probleme, 'Keine Probleme oder Behinderungen gemeldet.');
const ausgefuehrteArbeiten = safe(body.ausgefuehrteArbeiten || body.arbeiten, 'Keine Angabe.');
const offeneArbeiten = safe(body.offeneArbeiten || body.offen, 'Keine offenen Arbeiten gemeldet.');
const aufgaben = Array.isArray(body.aufgaben) ? body.aufgaben : safe(body.aufgaben).split('\n').filter(Boolean);
const fotoHinweise = Array.isArray(body.fotoHinweise) ? body.fotoHinweise : safe(body.fotoHinweise).split('\n').filter(Boolean);

const subject = `Tagesbericht SHK - ${projekt} - ${abschnitt} - ${datum}`;

const fileList = files.length
  ? files.map((file) => `- ${file.fileName} (${file.mimeType})`).join('\n')
  : 'Keine Fotos/Dateien hochgeladen.';

const reportText = [
  'Tagesbericht SHK-Heizungsmodernisierung',
  '',
  `Projekt: ${projekt}`,
  `Abschnitt: ${abschnitt}`,
  `Datum: ${datum}`,
  `Monteur / Team: ${team}`,
  `Status: ${status}`,
  '',
  'Erledigte Aufgaben:',
  aufgaben.length ? aufgaben.map((item) => `- ${item}`).join('\n') : 'Keine Aufgaben uebergeben.',
  '',
  'Material fehlt:',
  materialFehlt,
  '',
  'Probleme / Behinderungen:',
  probleme,
  '',
  'Ausgefuehrte Arbeiten:',
  ausgefuehrteArbeiten,
  '',
  'Offene Arbeiten:',
  offeneArbeiten,
  '',
  'Foto-Hinweise:',
  fotoHinweise.length ? fotoHinweise.map((item) => `- ${item}`).join('\n') : 'Keine Foto-Hinweise uebergeben.',
  '',
  'Hochgeladene Fotos / Dateien:',
  fileList,
].join('\n');

const reportHtml = reportText
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\n/g, '<br>');

return [{
  json: {
    projekt,
    abschnitt,
    datum,
    team,
    status,
    materialFehlt,
    probleme,
    ausgefuehrteArbeiten,
    offeneArbeiten,
    aufgaben,
    fotoHinweise,
    uploadedFiles: files,
    subject,
    reportText,
    reportHtml,
    receivedAt: new Date().toISOString(),
  },
  binary,
}];
